package com.lifepulse.notification;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;import com.lifepulse.common.IdGenerator;import com.lifepulse.entity.UserNotification;import com.lifepulse.mapper.UserNotificationMapper;import org.springframework.stereotype.Service;import java.time.LocalDateTime;import java.util.List;
@Service public class NotificationService { private final UserNotificationMapper mapper;private final IdGenerator ids;public NotificationService(UserNotificationMapper m,IdGenerator i){mapper=m;ids=i;} public void notify(Long user,String title,String content,String type){UserNotification n=new UserNotification();n.setId(ids.nextId());n.setUserId(user);n.setTitle(title);n.setContent(content);n.setType(type);n.setReadStatus(false);n.setCreatedAt(LocalDateTime.now());mapper.insert(n);} public List<UserNotification> mine(Long u){return mapper.selectList(new LambdaQueryWrapper<UserNotification>().eq(UserNotification::getUserId,u).orderByDesc(UserNotification::getCreatedAt));} public void read(Long id,Long u){mapper.update(null,new LambdaUpdateWrapper<UserNotification>().eq(UserNotification::getId,id).eq(UserNotification::getUserId,u).set(UserNotification::getReadStatus,true));}}
